mapper.select:
SELECT id, username, login_time AS loginTime, login_ip AS loginIp,
       login_location AS loginLocation, browser, os, status, msg
FROM sys_login_log

    deleted = 0

        AND username LIKE CONCAT('%', #{query.username}, '%')


        AND status = #{query.status}


        AND login_time >= #{query.beginTime}


        AND login_time <= #{query.endTime}


ORDER BY login_time DESC
